use poseidon::poseidon2::Poseidon2;
use std::field::bn254;

// keccak256("tornado") % BN254_FIELD_SIZE
global MERKLE_TREE_DEFAULT_ZERO: Field = 0x2fe54c60d3acabf3343a35b6eba15db4821b340f76e741e2249685ed4899af6c;

pub fn compute_merkle_root<let LEVELS: u32>(leaf: Field, path_elements: [Field; LEVELS], path_indices: Field) -> Field {
    let path_bits = path_indices.to_le_bits::<LEVELS>();

    let mut current_hash = leaf;

    for i in 0..LEVELS {
        let (left, right) = if path_bits[i] {
            (path_elements[i], current_hash)
        } else {
            (current_hash, path_elements[i])
        };
        current_hash = Poseidon2::hash::<2>([left, right], 2);
    }

    current_hash
}

// Verifies that an indexed Merkle leaf (leaf_key, leaf_next_key) exists at the given path.
// Does NOT check range ordering -- callers must add their own range assertions.
fn verify_indexed_leaf<let LEVELS: u32>(
    root: Field,
    leaf_key: Field,
    leaf_next_key: Field,
    path_elements: [Field; LEVELS],
    path_index: Field,
) {
    let leaf_hash = Poseidon2::hash::<2>([leaf_key, leaf_next_key], 2);
    let computed_root = compute_merkle_root::<LEVELS>(leaf_hash, path_elements, path_index);
    assert(computed_root == root);
}

// Proves each key is NOT in the indexed Merkle tree (non-membership).
// For each key: leaf_key < key < leaf_next_key, and the leaf exists in the tree.
pub fn verify_exclusion_proofs<let N: u32, let LEVELS: u32>(
    root: Field,
    keys: [Field; N],
    leaf_keys: [Field; N],
    leaf_next_keys: [Field; N],
    path_elements: [[Field; LEVELS]; N],
    path_indices: [Field; N],
) {
    for i in 0..N {
        bn254::assert_lt(leaf_keys[i], keys[i]);
        if leaf_next_keys[i] != 0 {
            bn254::assert_lt(keys[i], leaf_next_keys[i]);
        }
        verify_indexed_leaf(
            root,
            leaf_keys[i],
            leaf_next_keys[i],
            path_elements[i],
            path_indices[i],
        );
    }
}

// Proves a key IS in the indexed Merkle tree (membership).
// The key itself is the leaf key in the indexed tree.
pub fn verify_inclusion_proof<let LEVELS: u32>(
    root: Field,
    key: Field,
    leaf_next_key: Field,
    path_elements: [Field; LEVELS],
    path_index: Field,
) {
    if leaf_next_key != 0 {
        bn254::assert_lt(key, leaf_next_key);
    }
    verify_indexed_leaf(root, key, leaf_next_key, path_elements, path_index);
}

// Test-only helper: builds a full Merkle tree from leaves.
// Not used in production circuits. MAX_NODES must be >= 2^levels.
fn compute_merkle_tree<let N_LEAVES: u32, let MAX_NODES: u32>(levels: u32, leaves: [Field; N_LEAVES]) -> Field {
    assert((1 << levels as u8) as u32 >= N_LEAVES, "tree too small to process all leaves");

    let mut buf: BoundedVec<Field, MAX_NODES> = BoundedVec::new();
    for i in 0..N_LEAVES {
        buf.push(leaves[i]);
    }

    let mut level_size: u32 = (1 << levels as u8) as u32;
    for _level in 0..levels {
        let num_pairs = level_size / 2;
        let count = buf.len();
        let mut next: BoundedVec<Field, MAX_NODES> = BoundedVec::new();
        for i in 0..num_pairs {
            let left_idx = i * 2;
            let right_idx = left_idx + 1;
            let left = if left_idx < count {
                buf.get(left_idx)
            } else {
                MERKLE_TREE_DEFAULT_ZERO
            };
            let right = if right_idx < count {
                buf.get(right_idx)
            } else {
                MERKLE_TREE_DEFAULT_ZERO
            };
            next.push(Poseidon2::hash::<2>([left, right], 2));
        }
        buf = next;
        level_size = num_pairs;
    }
    buf.get(0)
}

#[test]
fn test_compute_merkle_tree_pass_1() {
    let levels = 5;
    let root = 0x1a3f2760c48ce20488041872caab9b32cf82dd974b4033febca4fe8f89ff7142;
    let leaves = [0x1, 0x2, 0x3, 0x4, 0x5, 0x6, 0x7, 0x8, 0x9, 0xa, 0xb, 0xc, 0xd, 0xe, 0xf, 0x10, 0x11, 0x12, 0x13, 0x14];

    let result = compute_merkle_tree::<20, 32>(levels, leaves);

    assert_eq(result, root);
}

#[test]
fn test_compute_merkle_tree_pass_2() {
    let levels = 4;
