use crate::subutxo::compute_subutxo_hash;
use poseidon::poseidon2::Poseidon2;

pub fn compute_commitment<let N_DEPOSIT_COMPONENTS: u32>(
    amount: Field,
    pubkey_hash: Field,
    blinding: Field,
    token: Field,
    note: Field,
    sub_deposit_ids: [Field; N_DEPOSIT_COMPONENTS],
    sub_deposit_amounts: [Field; N_DEPOSIT_COMPONENTS],
    nullifier_secret: Field,
) -> Field {
    let sub_hash = compute_subutxo_hash::<N_DEPOSIT_COMPONENTS>(sub_deposit_ids, sub_deposit_amounts);
    Poseidon2::hash::<7>(
        [amount, pubkey_hash, blinding, token, note, sub_hash, nullifier_secret],
        7,
    )
}

pub fn compute_nullifier(commitment: Field, path_index: Field, chain_id: Field, nullifier_secret: Field) -> Field {
    Poseidon2::hash::<4>([commitment, path_index, chain_id, nullifier_secret], 4)
}

