use crate::merkleproof;
use crate::note::{compute_commitment, compute_nullifier};
use crate::subutxo::validate_and_accumulate;
use crate::utils::{AMOUNT_BIT_SIZE, assert_all_unique, assert_unique_nonzero_slots, pin_public_input};
use poseidon::poseidon2::Poseidon2;
use schnorr;
use std::embedded_curve_ops::EmbeddedCurvePoint;

// Domain separator for spend-auth Schnorr challenge.
// message: "bermudabay:stx:spend-auth:schnorr:v1"
pub global SCHNORR_DOMAIN: Field = 18593004833411356993981768246051920231328811611081460266067910279816360120902;

fn compute_stx_hash<let N_INS: u32, let N_OUTS: u32>(
    chain_id: Field,
    root: Field,
    public_amount: Field,
    ext_data_hash: Field,
    recipient: Field,
    in_nullifier: [Field; N_INS],
    out_commitment: [Field; N_OUTS],
) -> Field {
    let inputs_nullifier_hash = Poseidon2::hash::<N_INS>(in_nullifier, N_INS);
    let outputs_commitment_hash = Poseidon2::hash::<N_OUTS>(out_commitment, N_OUTS);
    Poseidon2::hash::<7>(
        [chain_id, root, public_amount, ext_data_hash, recipient, inputs_nullifier_hash, outputs_commitment_hash],
        7,
    )
}

fn assert_conservation<let N_DEPOSIT_ID_SLOTS: u32>(
    sum_ins: Field,
    sum_outs: Field,
    public_amount: Field,
    public_deposit_id_deltas: [Field; N_DEPOSIT_ID_SLOTS],
    sum_in_by_deposit_id: [Field; N_DEPOSIT_ID_SLOTS],
    sum_out_by_deposit_id: [Field; N_DEPOSIT_ID_SLOTS],
) {
    let mut sum_public_deposits: Field = 0;
    for t in 0..N_DEPOSIT_ID_SLOTS {
        sum_public_deposits += public_deposit_id_deltas[t];
    }
    assert(sum_public_deposits == public_amount);

    for t in 0..N_DEPOSIT_ID_SLOTS {
        assert(sum_in_by_deposit_id[t] + public_deposit_id_deltas[t] == sum_out_by_deposit_id[t]);
    }

    assert((sum_ins + public_amount) == sum_outs);
}

pub fn stx_verifier<let CHAIN_ID: u32, let LEVELS: u32, let N_INS: u32, let N_OUTS: u32, let N_DEPOSIT_COMPONENTS: u32, let N_DEPOSIT_ID_SLOTS: u32>(
    root: Field,
    public_amount: Field,
    ext_data_hash: Field,
    recipient: Field,
    deposit_id_slots: [Field; N_DEPOSIT_ID_SLOTS],
    public_deposit_id_deltas: [Field; N_DEPOSIT_ID_SLOTS],
    in_nullifier: [Field; N_INS],
    in_amount: [Field; N_INS],
    in_pubkey_x: Field,
    in_pubkey_y: Field,
    in_transaction_signature: [Field; 4],
    in_blinding: [Field; N_INS],
    in_nullifier_secret: [Field; N_INS],
    token: Field,
    in_note: [Field; N_INS],
    in_path_indices: [Field; N_INS],
    in_path_elements: [[Field; LEVELS]; N_INS],
    in_sub_deposit_ids: [[Field; N_DEPOSIT_COMPONENTS]; N_INS],
    in_sub_deposit_amounts: [[Field; N_DEPOSIT_COMPONENTS]; N_INS],
    out_commitment: [Field; N_OUTS],
    out_amount: [Field; N_OUTS],
    out_pubkey_hash: [Field; N_OUTS],
    out_blinding: [Field; N_OUTS],
    out_nullifier_secret: [Field; N_OUTS],
    out_note: [Field; N_OUTS],
    out_sub_deposit_ids: [[Field; N_DEPOSIT_COMPONENTS]; N_OUTS],
    out_sub_deposit_amounts: [[Field; N_DEPOSIT_COMPONENTS]; N_OUTS],
) {
    let chain_id = CHAIN_ID as Field;

    assert_unique_nonzero_slots(deposit_id_slots);

    let stx_hash = compute_stx_hash(
        chain_id,
        root,
        public_amount,
        ext_data_hash,
        recipient,
        in_nullifier,
        out_commitment,
    );

    // -- Verify spend-auth signature (single spender per circuit execution) --
    let pubkey_point = EmbeddedCurvePoint { x: in_pubkey_x, y: in_pubkey_y };
    let pubkey_hash = Poseidon2::hash::<2>([in_pubkey_x, in_pubkey_y], 2);
    assert(
        schnorr::verify_signature(
            pubkey_point,
            in_transaction_signature,
            stx_hash,
            SCHNORR_DOMAIN,
        ),
    );

    // -- Verify inputs --
    let mut sum_ins: Field = 0;
    let mut sum_in_by_deposit_id: [Field; N_DEPOSIT_ID_SLOTS] = [0; N_DEPOSIT_ID_SLOTS];

    for i in 0..N_INS {
        let commitment = compute_commitment::<N_DEPOSIT_COMPONENTS>(
            in_amount[i],
            pubkey_hash,
            in_blinding[i],
            token,
            in_note[i],
            in_sub_deposit_ids[i],
            in_sub_deposit_amounts[i],
            in_nullifier_secret[i],
        );
        let nullifier = compute_nullifier(
            commitment,
            in_path_indices[i],
            chain_id,
            in_nullifier_secret[i],
        );
        assert(nullifier == in_nullifier[i]);

        if in_amount[i] != 0 {
            let merkle_root = merkleproof::compute_merkle_root(commitment, in_path_elements[i], in_path_indices[i]);
            assert(merkle_root == root);
        }

        // Input amounts don't need range checks - they were checked as outputs in prior transactions.
        sum_in_by_deposit_id = validate_and_accumulate(
            in_amount[i],
            in_sub_deposit_ids[i],
            in_sub_deposit_amounts[i],
            deposit_id_slots,
            sum_in_by_deposit_id,
        );
        sum_ins += in_amount[i];
    }

    // -- Verify outputs --
    let mut sum_outs: Field = 0;
    let mut sum_out_by_deposit_id: [Field; N_DEPOSIT_ID_SLOTS] = [0; N_DEPOSIT_ID_SLOTS];

    for i in 0..N_OUTS {
        let commitment = compute_commitment::<N_DEPOSIT_COMPONENTS>(
            out_amount[i],
            out_pubkey_hash[i],
            out_blinding[i],
            token,
            out_note[i],
            out_sub_deposit_ids[i],
            out_sub_deposit_amounts[i],
            out_nullifier_secret[i],
        );
        assert(commitment == out_commitment[i]);

        out_amount[i].assert_max_bit_size::<AMOUNT_BIT_SIZE>();

        sum_out_by_deposit_id = validate_and_accumulate(
            out_amount[i],
            out_sub_deposit_ids[i],
            out_sub_deposit_amounts[i],
            deposit_id_slots,
            sum_out_by_deposit_id,
        );
        sum_outs += out_amount[i];
    }

    // -- Cross-checks --
    assert_all_unique(in_nullifier);
    assert_conservation(
        sum_ins,
        sum_outs,
        public_amount,
        public_deposit_id_deltas,
        sum_in_by_deposit_id,
        sum_out_by_deposit_id,
    );

    pin_public_input(ext_data_hash);
}

