use crate::utils::{AMOUNT_BIT_SIZE, is_equal};
use poseidon::poseidon2::Poseidon2;

pub fn compute_subutxo_hash<let N_DEPOSIT_COMPONENTS: u32>(
    sub_deposit_ids: [Field; N_DEPOSIT_COMPONENTS],
    sub_deposit_amounts: [Field; N_DEPOSIT_COMPONENTS],
) -> Field {
    let mut data: [Field; N_DEPOSIT_COMPONENTS * 2] = [0; N_DEPOSIT_COMPONENTS * 2];
    for i in 0..N_DEPOSIT_COMPONENTS {
        data[i] = sub_deposit_ids[i];
        data[i + N_DEPOSIT_COMPONENTS] = sub_deposit_amounts[i];
    }
    Poseidon2::hash::<N_DEPOSIT_COMPONENTS * 2>(data, N_DEPOSIT_COMPONENTS * 2)
}

/// Validates sub-UTXO decomposition for a single note and accumulates per-slot totals.
/// Checks: each sub-amount fits in AMOUNT_BIT_SIZE bits, sub-amounts sum to note amount,
/// each non-zero sub-UTXO maps to exactly one deposit_id slot.
pub fn validate_and_accumulate<let N_DEPOSIT_COMPONENTS: u32, let N_DEPOSIT_ID_SLOTS: u32>(
    note_amount: Field,
    sub_deposit_ids: [Field; N_DEPOSIT_COMPONENTS],
    sub_deposit_amounts: [Field; N_DEPOSIT_COMPONENTS],
    deposit_id_slots: [Field; N_DEPOSIT_ID_SLOTS],
    mut accumulator: [Field; N_DEPOSIT_ID_SLOTS],
) -> [Field; N_DEPOSIT_ID_SLOTS] {
    let mut note_sum: Field = 0;
    for k in 0..N_DEPOSIT_COMPONENTS {
        sub_deposit_amounts[k].assert_max_bit_size::<AMOUNT_BIT_SIZE>();
        note_sum += sub_deposit_amounts[k];
    }
    assert(note_sum == note_amount);

    for k in 0..N_DEPOSIT_COMPONENTS {
        let sub_amount = sub_deposit_amounts[k];
        let sub_deposit_id = sub_deposit_ids[k];
        if sub_amount != 0 {
            assert(sub_deposit_id != 0);
            let mut match_count: Field = 0;
            for t in 0..N_DEPOSIT_ID_SLOTS {
                let matches = is_equal(sub_deposit_id, deposit_id_slots[t]);
                match_count += matches;
                accumulator[t] += sub_amount * matches;
            }
            assert(match_count == 1);
        }
    }
    accumulator
}

// -- Tests --

#[test]
fn test_compute_subutxo_hash_nonzero() {
    let ids = [1, 2];
    let amounts = [100, 200];
    let hash = compute_subutxo_hash(ids, amounts);
    // Just verify it produces a deterministic non-zero value.
    assert(hash != 0);
}

#[test]
fn test_compute_subutxo_hash_all_zero() {
    let ids = [0, 0];
    let amounts = [0, 0];
    let hash = compute_subutxo_hash(ids, amounts);
    assert(hash != 0); // Poseidon2 of zeros is still non-zero.
}

#[test]
fn test_compute_subutxo_hash_different_inputs_different_outputs() {
    let h1 = compute_subutxo_hash([1, 0], [100, 0]);
    let h2 = compute_subutxo_hash([2, 0], [100, 0]);
    assert(h1 != h2);
}

#[test]
fn test_validate_and_accumulate_pass() {
    let slots = [1, 2, 0, 0];
    let acc = [0, 0, 0, 0];
    let result = validate_and_accumulate(100, [1, 0], [100, 0], slots, acc);
    assert(result[0] == 100);
    assert(result[1] == 0);
}

#[test]
fn test_validate_and_accumulate_multi_deposit() {
    let slots = [1, 2, 0, 0];
    let acc = [0, 0, 0, 0];
    let result = validate_and_accumulate(150, [1, 2], [100, 50], slots, acc);
    assert(result[0] == 100);
    assert(result[1] == 50);
}

#[test(should_fail)]
fn test_validate_and_accumulate_fail_sum_mismatch() {
    let slots = [1, 0, 0, 0];
    let acc = [0, 0, 0, 0];
    // Sub-amounts (100 + 50 = 150) don't match note_amount (100).
    let _ = validate_and_accumulate(100, [1, 1], [100, 50], slots, acc);
}

#[test(should_fail)]
fn test_validate_and_accumulate_fail_zero_id_nonzero_amount() {
    let slots = [1, 0, 0, 0];
    let acc = [0, 0, 0, 0];
    // deposit_id=0 with amount=100 is invalid.
    let _ = validate_and_accumulate(100, [0, 0], [100, 0], slots, acc);
}

#[test(should_fail)]
fn test_validate_and_accumulate_fail_id_not_in_slots() {
    let slots = [1, 2, 0, 0];
    let acc = [0, 0, 0, 0];
    // deposit_id=99 is not in slots.
    let _ = validate_and_accumulate(100, [99, 0], [100, 0], slots, acc);
}

