pub global AMOUNT_BIT_SIZE: u32 = 248;

// a == b ? 1 : 0
pub fn is_equal(a: Field, b: Field) -> Field {
    Field::from(a == b)
}

/// Forces the compiler to retain a public input that is not otherwise constrained.
pub fn pin_public_input(value: Field) {
    let _ = std::hint::black_box(value);
}

/// Asserts all elements in an array are pairwise distinct.
pub fn assert_all_unique<let N: u32>(values: [Field; N]) {
    for i in 0..N {
        for j in (i + 1)..N {
            assert(values[i] != values[j]);
        }
    }
}

/// Asserts all non-zero elements in an array are pairwise distinct.
pub fn assert_unique_nonzero_slots<let N: u32>(slots: [Field; N]) {
    for a in 0..N {
        for b in (a + 1)..N {
            if slots[a] * slots[b] != 0 {
                assert(slots[a] != slots[b]);
            }
        }
    }
}

// -- Tests --

#[test]
fn test_is_equal_same() {
    assert(is_equal(42, 42) == 1);
}

#[test]
fn test_is_equal_different() {
    assert(is_equal(42, 43) == 0);
}

#[test]
fn test_is_equal_zero() {
    assert(is_equal(0, 0) == 1);
    assert(is_equal(0, 1) == 0);
}

#[test]
fn test_assert_all_unique_pass() {
    assert_all_unique([1, 2, 3, 4]);
}

#[test(should_fail)]
fn test_assert_all_unique_fail_duplicates() {
    assert_all_unique([1, 2, 3, 1]);
}

#[test]
fn test_assert_unique_nonzero_slots_pass() {
    assert_unique_nonzero_slots([1, 2, 3, 0, 0]);
}

#[test]
fn test_assert_unique_nonzero_slots_zeros_ok() {
    assert_unique_nonzero_slots([0, 0, 0, 0]);
}

#[test(should_fail)]
fn test_assert_unique_nonzero_slots_fail() {
    assert_unique_nonzero_slots([1, 2, 1, 0]);
}

