use common::{SCHNORR_DOMAIN, stx_verifier, utils::{AMOUNT_BIT_SIZE, is_equal}};
use poseidon::poseidon2::Poseidon2;
use schnorr;
use std::embedded_curve_ops::EmbeddedCurvePoint;
mod test;

// Cap on the compliance-signed deposit deadline. 64 bits is far above any realistic
// chain block height, but bounding the value ensures the on-chain
// `block.number <= expiry_block_number` comparison cannot be defeated by a
// field-wraparound value (e.g. a maliciously-signed `field_modulus - 1`).
global EXPIRY_BIT_SIZE: u32 = 64;

pub fn circuit<let CHAIN_ID: u32, let LEVELS: u32, let INDEXED_LEVELS: u32, let N_INS: u32, let N_OUTS: u32, let N_DEPOSIT_COMPONENTS: u32, // The maximum number of sub-UTXO components a note can have.
let N_DEPOSIT_ID_SLOTS: u32 // The number of slots for the deposit_id handled by the stx-transaction.
>(
    root: Field, // pub
    // extAmount = external amount used for deposits and withdrawals
    // correct extAmount range is enforced on the smart contract
    // publicAmount = extAmount - relayerFee
    public_amount: Field, // pub
    ext_data_hash: Field, // pub
    recipient: Field, // pub - external recipient binding for Safe withdrawals
    deposit_funder: Field, // pub - funder address bound in compliance signature
    // Compliance-signed deadline. Public so Solidity can read it and enforce
    // `block.number <= expiry_block_number` against the live chain head;
    // the circuit only proves the value is bound by the compliance signature.
    expiry_block_number: Field, // pub
    // Tx type flags
    // If 0, it is transfer, split, or merge.
    is_deposit: Field, // 0/1
    // sub-UTXO: private list of deposit_ids this stx-tx can operate on.
    deposit_id_slots: [Field; N_DEPOSIT_ID_SLOTS],
    // sub-UTXO: public per-deposit_id delta (sum equals public_amount).
    public_deposit_id_deltas: [Field; N_DEPOSIT_ID_SLOTS], // pub
    // compliance signature (deposit tx only)
    compliance_signature: [Field; 4],
    compliance_deposit_id: Field,
    compliance_pubkey_x: Field, // pub
    compliance_pubkey_y: Field, // pub
    // data for transaction inputs
    in_nullifier: [Field; N_INS], // pub
    in_amount: [Field; N_INS],
    in_pubkey_x: Field,
    in_pubkey_y: Field,
    // signature = [R.x, R.y, z.lo, z.hi]
    in_transaction_signature: [Field; 4],
    in_blinding: [Field; N_INS],
    in_nullifier_secret: [Field; N_INS],
    token: Field,
    in_note: [Field; N_INS],
    in_path_indices: [Field; N_INS],
    in_path_elements: [[Field; LEVELS]; N_INS],
    // sub-UTXO: per-input deposit_id allocation; amounts sum to in_amount[i].
    in_sub_deposit_ids: [[Field; N_DEPOSIT_COMPONENTS]; N_INS],
    in_sub_deposit_amounts: [[Field; N_DEPOSIT_COMPONENTS]; N_INS],
    // data for transaction outputs
    out_commitment: [Field; N_OUTS], // pub
    out_amount: [Field; N_OUTS],
    out_pubkey_hash: [Field; N_OUTS],
    out_blinding: [Field; N_OUTS],
    out_nullifier_secret: [Field; N_OUTS],
    out_note: [Field; N_OUTS],
    // sub-UTXO: per-output deposit_id breakdown; amounts sum to out_amount[i].
    out_sub_deposit_ids: [[Field; N_DEPOSIT_COMPONENTS]; N_OUTS],
    out_sub_deposit_amounts: [[Field; N_DEPOSIT_COMPONENTS]; N_OUTS],
) {
    let chain_id = CHAIN_ID as Field;
    assert(is_deposit * (is_deposit - 1) == 0);

    // Range-check public_amount to prevent withdrawals (negative field values).
    let _ = public_amount.to_le_bits::<AMOUNT_BIT_SIZE>();

    stx_verifier::<CHAIN_ID, LEVELS, N_INS, N_OUTS, N_DEPOSIT_COMPONENTS, N_DEPOSIT_ID_SLOTS>(
        root,
        public_amount,
        ext_data_hash,
        recipient,
        deposit_id_slots,
        public_deposit_id_deltas,
        in_nullifier,
        in_amount,
        in_pubkey_x,
        in_pubkey_y,
        in_transaction_signature,
        in_blinding,
        in_nullifier_secret,
        token,
        in_note,
        in_path_indices,
        in_path_elements,
        in_sub_deposit_ids,
        in_sub_deposit_amounts,
        out_commitment,
        out_amount,
        out_pubkey_hash,
        out_blinding,
        out_nullifier_secret,
        out_note,
        out_sub_deposit_ids,
        out_sub_deposit_amounts,
    );
    // Branching by tx type
    if is_deposit == 1 {
        assert(deposit_funder != 0);
        assert(compliance_deposit_id != 0);
        // Bound the expiry so the on-chain `block.number <= expiry_block_number`
        // comparison can't be defeated by a field-wraparound value.
        expiry_block_number.assert_max_bit_size::<EXPIRY_BIT_SIZE>();
        // Construct compliance message
        let compliance_token = token;
        let outputs_commitment_hash = Poseidon2::hash::<N_OUTS>(out_commitment, N_OUTS);
        let computed_compliance_hash = Poseidon2::hash::<7>(
            [
                chain_id,
                compliance_token,
                public_amount,
                compliance_deposit_id,
                outputs_commitment_hash,
                deposit_funder,
                expiry_block_number,
            ],
            7,
        );
        // Compliance server's signature check (Schnorr over Grumpkin).
        // TODO: use different domain separator
        let compliance_pubkey = EmbeddedCurvePoint { x: compliance_pubkey_x, y: compliance_pubkey_y };
        assert(
            schnorr::verify_signature(
                compliance_pubkey,
                compliance_signature,
                computed_compliance_hash,
                SCHNORR_DOMAIN,
            ),
        );
        // compliance_deposit_id must match one of the deposit_id_slots array handled
        // by this transaction
        let mut found: Field = 0;
        for t in 0..N_DEPOSIT_ID_SLOTS {
            let flag = is_equal(compliance_deposit_id, deposit_id_slots[t]);
            found += flag;
        }
        assert(found == 1);
        // Sum amounts across all sub-UTXOs that match compliance_deposit_id.
        let mut compliance_amount_sum: Field = 0;
        for i in 0..N_OUTS {
            for k in 0..N_DEPOSIT_COMPONENTS {
                let flag = is_equal(out_sub_deposit_ids[i][k], compliance_deposit_id);
                compliance_amount_sum += out_sub_deposit_amounts[i][k] * flag;
            }
        }
        assert(compliance_amount_sum == public_amount);
    }
    // transfer, split, merge
    else {
        assert(public_amount == 0);
        for t in 0..N_DEPOSIT_ID_SLOTS {
            assert(public_deposit_id_deltas[t] == 0);
        }
        // Force unused on the non-deposit branch so callers can't smuggle a meaningful
        // expiry through; also pins the public input so the optimizer can't drop it.
        assert(expiry_block_number == 0);
    }
}
